/**
 * Map for quick lookup by account code
 */
export const pcgByCode: Map<string, PCGAccount> = new Map(
  pcgAccounts.map((account) => [account.code, account])
)

/**
 * Filter accounts by class number (1-7)
 */
export function pcgByClass(classNumber: number): PCGAccount[] {
  return pcgAccounts.filter((account) => account.class === classNumber)
}

/**
 * Search accounts by code prefix or label text (case-insensitive)
 */
export function searchPCG(query: string): PCGAccount[] {
  const normalizedQuery = query
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')

  return pcgAccounts.filter((account) => {
    const normalizedCode = account.code.toLowerCase()
    const normalizedLabel = account.label
      .toLowerCase()
      .normalize('NFD')
      .replace(/[\u0300-\u036f]/g, '')

    return (
      normalizedCode.startsWith(normalizedQuery) ||
      normalizedLabel.includes(normalizedQuery)
    )
  })
}
